package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenPatronaalRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoon;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.GewoonLoonFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.AantalKalenderDagen;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckBvBedrijfsVoertuig;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Milieuvriendelijk;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import com.google.common.collect.ImmutableSet;
import org.joda.time.LocalDate;

import java.util.Collection;
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;
import java.util.Set;

public class SocialeBijdrageVoertuig {

    private static final Set<Hoedanigheid> HOEDANIGHEID_ZONDER_CTRL_SOL_VOERTUIG = ImmutableSet.of(Hoedanigheid.MANDATARISSEN, Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD);
    private static final int AKE_CODE_770 = 770;
    private static final int AKE_EXT_20 = 20;
    private static final int PRECISIE = 2;

    public void bereken(RekenContext context, Opdracht opdracht, RegulManager regulManager) {
        if (opdracht.getHoedanigheid() == Hoedanigheid.VRIJWILLIGERS) {
            return;
        }
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        Money patronaleBijdrageVoertuig = bepaalBedragSolidariteitsBijdrageVoertuig(opdracht, rekenTijd);
        Opper opper = context.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);

        if (patronaleBijdrageVoertuig.signum() == 0 && isNummerPlaatIngevuld(opper) && !HOEDANIGHEID_ZONDER_CTRL_SOL_VOERTUIG.contains(opdracht.getHoedanigheid())) {
            regulManager.doRegulException(opdracht, Regulkode.LK770_ZONDER_PATRONALE);
        } else if (patronaleBijdrageVoertuig.signum() != 0) {
            boolean isMilieuVriendelijk = opper.getRszppo().getMilieuvriendelijkeWagen() == Milieuvriendelijk.WEL_BETREKKING;
            RekenPatronaalRszKey patronaalKey =
                    isMilieuVriendelijk ? RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_3_KEY : RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_KEY;
            context.put(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_KEY, patronaleBijdrageVoertuig);

            LoonElementManager manager = context.getLoonElementManager();
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
            LoonElementChecker checkBvBedrijfsVoertuig = new CheckBvBedrijfsVoertuig();
            Money totaalBasis = RekenTools.getSomProperty(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY, loonElementen, checkBvBedrijfsVoertuig);
            if (totaalBasis.signum() != 0) {
                BedragVerdelerFactory.verdeelBedragVolgensBasisPut(patronaalKey, patronaleBijdrageVoertuig,
                        RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY, totaalBasis, loonElementen, checkBvBedrijfsVoertuig);
            } else {
                LoonCodeManager loonCodeManager = context.getUnchecked(RekenChainKey.LOONCODE_MANAGER_KEY);
                GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
                AardKodeExtensie defaultLoonCode = gewoonLoon.createDefaultLoonCodeSocialeBijdrageVoertuig();
                LoonElement element = manager.getOrCreateLoonElement(opper, defaultLoonCode);
                element.putProperty(patronaalKey, patronaleBijdrageVoertuig);
            }
            loonElementen.stream()
                    .filter(x -> x.getAardKodeExtensie().getCode() == AKE_CODE_770 && x.getAardKodeExtensie().getExtensie() == AKE_EXT_20)
                    .forEach(x -> RekenTools.replaceKey(x, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_KEY, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_2_KEY));
        }
    }

    private boolean isNummerPlaatIngevuld(Opper opper) {
        return opper.getRszppo().getNummerPlaat() != null && !opper.getRszppo().getNummerPlaat().isBlank();
    }

    /**
     * Als het bedrag wijzigt in de loop van de maand (door een verandering van wagen),
     * dan nemen we het bedrag dat in aantal kalenderdagen het meest voorkomt.
     * Bij een gelijk aantal kalenderdagen kiezen we voor het laatst gebruikte bedrag
     */
    private static Money bepaalBedragSolidariteitsBijdrageVoertuig(Opdracht opdracht, RekenTijd rekenTijd) {
        Map<Money, Integer> bedragToDagen = new HashMap<>();
        Map<Money, LocalDate> bedragToDatumActief = new HashMap<>();
        for (Opper opper : opdracht.getOpperSlices()) {
            Money bedrag = Money.ZERO;
            if (Objects.nonNull(opper.getRszppo().getSolidariteitsBijdrageVoertuig().getAmount())) {
                bedrag = opper.getRszppo().getSolidariteitsBijdrageVoertuig().round(PRECISIE);
            }

            Integer kalenderdagen = bedragToDagen.get(bedrag);
            if (kalenderdagen == null) {
                kalenderdagen = 0;
            }
            LocalDateInterval doorsnede = opper.getActualInterval().overlap(rekenTijd.rekenPeriode);
            kalenderdagen += AantalKalenderDagen.inInterval(doorsnede).intValue();
            bedragToDagen.put(bedrag, kalenderdagen);
            LocalDate datum = bedragToDatumActief.get(bedrag);
            if (datum == null || datum.compareTo(doorsnede.getStart()) < 0) {
                bedragToDatumActief.put(bedrag, doorsnede.getStart());
            }
        }
        Money patronaleBijdrageVoertuig = Money.ZERO;
        Integer kalenderdagenActief = 0;
        LocalDate datumActief = rekenTijd.beginDatum;
        for (Map.Entry<Money, Integer> entrySet : bedragToDagen.entrySet()) {
            Integer kalenderDagen = entrySet.getValue();
            Money bedrag = entrySet.getKey();
            LocalDate datum = bedragToDatumActief.get(bedrag);
            if ((kalenderDagen.compareTo(kalenderdagenActief) > 0 || (kalenderDagen.equals(kalenderdagenActief) && datum.compareTo(datumActief) > 0))
                    && bedrag.signum() != 0) {
                patronaleBijdrageVoertuig = bedrag;
                kalenderdagenActief = kalenderDagen;
                datumActief = datum;
            }
        }
        return patronaleBijdrageVoertuig;
    }
}
